class Solution {
    public int strongPasswordChecker(String password) {
        int missingTypes = 3;
        if (hasLowercase(password)) missingTypes--;
        if (hasUppercase(password)) missingTypes--;
        if (hasDigit(password)) missingTypes--;

        int ones = 0, twos = 0;
        int count = 1;
        for (int i = 1; i < password.length(); i++) {
            if (password.charAt(i) == password.charAt(i - 1)) {
                count++;
            } else {
                if (count >= 3) {
                    if (count % 3 == 0) ones++;
                    else if (count % 3 == 1) twos++;
                }
                count = 1;
            }
        }
        if (count >= 3) {
            if (count % 3 == 0) ones++;
            else if (count % 3 == 1) twos++;
        }

        if (password.length() < 6) {
            return Math.max(6 - password.length(), missingTypes);
        } else if (password.length() <= 20) {
            return Math.max(missingTypes, ones + twos);
        } else {
            int del = password.length() - 20;
            int res = del;
            del -= Math.min(del, ones);
            del -= Math.min(del, twos);
            res += Math.max(missingTypes, (del + 2) / 3);
            return res;
        }
    }

    private boolean hasLowercase(String s) {
        for (char c : s.toCharArray()) {
            if (Character.isLowerCase(c)) return true;
        }
        return false;
    }

    private boolean hasUppercase(String s) {
        for (char c : s.toCharArray()) {
            if (Character.isUpperCase(c)) return true;
        }
        return false;
    }

    private boolean hasDigit(String s) {
        for (char c : s.toCharArray()) {
            if (Character.isDigit(c)) return true;
        }
        return false;
    }
}
